bson/_cbsonmodule.c:1623:        raw_bson_document_bytes_obj = PyObject_GetAttrString(dict, "raw");
bson/_cbsonmodule.c:1664:    if (PyMapping_HasKeyString(value, "$ref") && PyMapping_HasKeyString(value, "$id")) { /* DBRef */
bson/_cbsonmodule.c:1665:        ref = PyMapping_GetItemString(value, "$ref");
bson/_cbsonmodule.c:1670:        id = PyMapping_GetItemString(value, "$id");
bson/_cbsonmodule.c:1676:        if (PyMapping_HasKeyString(value, "$db")) {
